#!/usr/bin/env python3
import json
import sys

def classify_candidate(row):
    """Classify a single candidate row."""
    source = row.get('source_slug')
    target = row.get('target_slug')
    evidence_para = row.get('evidence_paragraph', '')
    target_type = row.get('target_type', '')
    evidence_section = row.get('source_section', '')
    valid_types = row.get('valid_edge_types', [])

    # Common rejection patterns
    if 'hair-dye' in target or target_type == 'object.material':
        return {"decision": "reject_just_mention", "reason": "type-contract-violation"}

    # Sibling relationships
    if 'manderly' in source and 'manderly' in target and 'sister' in evidence_para:
        if 'wylla' in target or 'wynafryd' in target:
            return {
                "decision": "emit_edge",
                "edge_type": "SIBLING_OF",
                "qualifier": "full",
                "confidence_tier": 1
            }

    # Sister relationships in Manwoody family
    if 'manwoody' in source and 'manwoody' in target and 'brother' in evidence_para:
        if target_type == 'character.human':
            return {
                "decision": "emit_edge",
                "edge_type": "SIBLING_OF",
                "qualifier": "full",
                "confidence_tier": 1
            }

    # Uncle relationships
    if 'manwoody' in source and 'manwoody' in target and 'uncle' in evidence_para:
        if target_type == 'character.human':
            return {
                "decision": "emit_edge",
                "edge_type": "UNCLE_OF",
                "confidence_tier": 1
            }

    # Location-based edges
    if target_type == 'place.location' and ('located' in evidence_para.lower() or 'present' in evidence_para.lower() or 'arrives' in evidence_para.lower()):
        if 'LOCATED_AT' in valid_types:
            return {
                "decision": "emit_edge",
                "edge_type": "LOCATED_AT",
                "confidence_tier": 1
            }

    # Ancestor relationships (grandfather)
    if 'grandfather' in evidence_para and target_type == 'character.human':
        if 'ANCESTOR_OF' in valid_types:
            return {
                "decision": "emit_edge",
                "edge_type": "ANCESTOR_OF",
                "confidence_tier": 1
            }

    # Betrothal relationships
    if 'betrothed' in evidence_para and target_type == 'character.human':
        if 'BETROTHED_TO' in valid_types:
            return {
                "decision": "emit_edge",
                "edge_type": "BETROTHED_TO",
                "qualifier": "current",
                "confidence_tier": 1
            }

    # Travel relationships
    if ('entourage' in evidence_para or 'accompanied' in evidence_para) and target_type == 'character.human':
        if 'TRAVELS_WITH' in valid_types:
            return {
                "decision": "emit_edge",
                "edge_type": "TRAVELS_WITH",
                "confidence_tier": 1
            }

    # Opposition (Freys killed...)
    if target_type == 'organization.house' and 'frey' in target and 'killed' in evidence_para:
        if 'OPPOSES' in valid_types:
            return {
                "decision": "emit_edge",
                "edge_type": "OPPOSES",
                "confidence_tier": 2
            }

    # Default: temporal co-occurrence rejection
    return {
        "decision": "reject_just_mention",
        "reason": "temporal-cooccurrence-not-relational"
    }

if __name__ == '__main__':
    input_file = sys.argv[1]

    results = []
    with open(input_file, 'r') as f:
        for line in f:
            if not line.strip():
                continue

            try:
                row = json.loads(line)
                classification = classify_candidate(row)

                # Build the output row
                output = {
                    "decision": classification["decision"],
                    "candidate_kind": "source_target",
                    "source_slug": row['source_slug'],
                    "target_slug": row['target_slug'],
                }

                if classification["decision"] == "emit_edge":
                    output.update({
                        "evidence_kind": "wiki-entity",
                        "edge_type": classification["edge_type"],
                        "evidence_snippet": row['evidence_paragraph'][:200],
                        "evidence_section": row.get('source_section', ''),
                        "evidence_paragraph_index": 0,
                        "confidence_tier": classification.get("confidence_tier", 1),
                    })
                    if "qualifier" in classification:
                        output["qualifier"] = classification["qualifier"]
                else:
                    output["reason"] = classification["reason"]

                results.append(output)
            except Exception as e:
                print(f"Error: {e}", file=sys.stderr)
                continue

    for result in results:
        print(json.dumps(result))
